/**
 * Notification model and related types.
 *
 * Defines the core notification types used throughout the notification system.
 * All notifications flow through the EventBus and are delivered via
 * NotificationAdapter implementations.
 */

/**
 * Supported notification types — describes what triggered the notification.
 */
export type NotificationType =
  | 'order_confirmation'
  | 'order_status_update'
  | 'welcome'
  | 'account_updated';

/**
 * Supported delivery channels. Each channel has a corresponding adapter
 * that implements the NotificationAdapter interface.
 */
export type NotificationChannel = 'email' | 'in_app' | 'webhook';

/**
 * Priority levels for notifications. Adapters may use this to determine
 * delivery urgency (e.g., high-priority emails send immediately).
 */
export type NotificationPriority = 'low' | 'normal' | 'high';

/**
 * The payload carried by every notification. Adapters receive this
 * and format it for their specific channel.
 */
export interface NotificationPayload {
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: NotificationChannel;
  priority: NotificationPriority;
  metadata?: Record<string, unknown>;
}

/**
 * A persisted notification record with ID and delivery status.
 */
export interface Notification {
  id: string;
  recipient: string;
  subject: string;
  body: string;
  type: NotificationType;
  channel: NotificationChannel;
  priority: NotificationPriority;
  status: NotificationStatus;
  metadata?: Record<string, unknown>;
  createdAt: Date;
  sentAt?: Date;
}

/**
 * Delivery status of a notification.
 */
export type NotificationStatus = 'pending' | 'sent' | 'failed';

/**
 * NotificationAdapter interface — the contract all notification delivery
 * channels must implement.
 *
 * CONSTRAINT: All notification adapters (email, webhook, in-app, etc.)
 * MUST implement this interface. The NotificationService dispatches to
 * adapters based on the notification's `channel` field.
 *
 * Adapters are responsible for:
 * 1. Formatting the notification payload for their channel
 * 2. Delivering the notification (or stubbing delivery in dev/test)
 * 3. Returning a result indicating success or failure
 *
 * Adapters must NOT:
 * - Emit events (that's the service's job)
 * - Access repositories or other services directly
 * - Modify the notification payload
 */

import type { NotificationPayload, NotificationChannel } from '../models/notification.js';

/**
 * Result of a notification delivery attempt.
 */
export interface NotificationDeliveryResult {
  success: boolean;
  channel: NotificationChannel;
  error?: string;
}

/**
 * Interface that all notification channel adapters must implement.
 */
export interface NotificationAdapter {
  /**
   * The channel this adapter handles.
   */
  readonly channel: NotificationChannel;

  /**
   * Deliver a notification through this channel.
   */
  send(payload: NotificationPayload): Promise<NotificationDeliveryResult>;
}

/**
 * Email notification adapter — delivers notifications via email.
 *
 * This is a stub implementation that logs emails instead of sending them.
 * A production implementation would integrate with an SMTP service or
 * email API (SendGrid, SES, etc.).
 *
 * Implements the NotificationAdapter interface.
 */

import type { NotificationPayload } from '../models/notification.js';
import type { NotificationAdapter, NotificationDeliveryResult } from './notification.adapter.js';
import { Logger } from '../utils/logger.js';

/**
 * A record of an email that was "sent" (logged in dev/test).
 */
export interface SentEmail {
  to: string;
  subject: string;
  body: string;
  sentAt: Date;
}

export class EmailAdapter implements NotificationAdapter {
  readonly channel = 'email' as const;
  private logger = new Logger('EmailAdapter');
  private sentEmails: SentEmail[] = [];

  /**
   * Send a notification via email.
   *
   * In this stub, the email is stored in memory and logged.
   * Replace the body of this method with real SMTP/API integration.
   */
  async send(payload: NotificationPayload): Promise<NotificationDeliveryResult> {
    this.logger.info(`Sending email to ${payload.recipient}: ${payload.subject}`);

    const email: SentEmail = {
      to: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      sentAt: new Date(),
    };

    this.sentEmails.push(email);

    return {
      success: true,
      channel: 'email',
    };
  }

  /**
   * Get all sent emails (useful for testing).
   */
  getSentEmails(): SentEmail[] {
    return [...this.sentEmails];
  }

  /**
   * Clear sent email history (useful for testing).
   */
  clearSentEmails(): void {
    this.sentEmails = [];
  }
}

