import type { User } from '../models/user.js';
import type { NotificationPayload } from '../models/notification.js';

export interface OrderCreatedEvent {
  type: 'order:created';
  order: Order;
  user: User;
  timestamp: Date;
}

export interface OrderStatusChangedEvent {
  type: 'order:status-changed';
  order: Order;
  previousStatus: string;
  newStatus: string;
  timestamp: Date;
}

export interface UserCreatedEvent {
  type: 'user:created';
  user: User;
  timestamp: Date;
}

export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

/**
 * Emitted when a notification needs to be sent. The NotificationService
 * listens for all domain events and emits this event for each notification
 * that should be delivered. Adapters consume this event via the service.
 */
export interface NotificationRequestedEvent {
  type: 'notification:requested';
  payload: NotificationPayload;
  timestamp: Date;
}

/**
 * Emitted after a notification has been sent (or failed).
 */
export interface NotificationSentEvent {
  type: 'notification:sent';
  notificationId: string;
  channel: string;
  success: boolean;
  error?: string;
  timestamp: Date;
}

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationRequestedEvent
  | NotificationSentEvent;

export type EventType = AppEvent['type'];

